sql:
SELECT COUNT(*) AS total_dependencies, license_type_id
FROM dependencies
GROUP BY license_type_id;

SELECT author_id, name
FROM authors
WHERE author_id IN (
    SELECT author_id
    FROM dependencies
)
AND author_id NOT IN (
    SELECT manager_id
    FROM departments
);

